var createTopic = (name, icon, customLinks = [], overrideId) => {
  const id = overrideId || generateId(name);
  return {
    id,
    name,
    icon,
    modes: ["Hackathon", "Personal", "Production"],
    quickLinks: [...globalTopicLinks[id] || [], ...customLinks]
  };
};

